import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    best_solution = None
    best_value = float('inf')
    evaluations = 0
    population_size = initial_population.shape[0]
    dimension = initial_population.shape[1]

    for idx in range(population_size):
        current_solution = np.copy(initial_population[idx])
        current_value = objective_function(current_solution)
        evaluations += 1

        if current_value < best_value:
            best_value = current_value
            best_solution = current_solution

    iterations = 30000 // population_size

    for _ in range(iterations):
        for idx in range(population_size):
            neighborhood = np.random.uniform(low=individual_lower, high=individual_upper, size=(5, dimension))
            for neighbor in neighborhood:
                if np.all(neighbor >= individual_lower) and np.all(neighbor <= individual_upper):
                    neighbor_value = objective_function(neighbor)
                    evaluations += 1
                    if neighbor_value < best_value:
                        best_value = neighbor_value
                        best_solution = neighbor

    return best_solution
